CREATE PROCEDURE assoc.sp_Dashboard_GetAdminSnapshot @TenantId INT, @AssociationId INT AS BEGIN SET NOCOUNT ON; SELECT CAST(ISNULL(ab.TotalRevenue, 0) AS DECIMAL(18,2)) AS TotalRevenue, CAST(ISNULL(ab.TotalOutstanding, 0) AS DECIMAL(18,2)) AS NetOutstanding, CAST(ISNULL(ab.TotalAdvanceCredits, 0) AS DECIMAL(18,2)) AS HeldAdvanceMoney, ISNULL(ab.UnitsWithCredit, 0) AS UnitsWithCredit, ISNULL(ab.TotalMembers, 0) AS TotalMembers, ISNULL(ab.CommitteeMembers, 0) AS CommitteeMembers, ISNULL(ab.PendingWorkOrders, 0) AS PendingWorkOrders, ab.LastUpdated FROM assoc.AssociationBalances ab WHERE ab.AssociationId = @AssociationId AND ab.TenantId = @TenantId; END